import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';

void main() {
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: Scaffold(
        appBar: AppBar(title: Text('HTTP Service Example')),
        body: Center(
          child: ElevatedButton(
            onPressed: fetchData,
            child: Text('Fetch Data'),
          ),
        ),
      ),
    );
  }

  Future<void> fetchData() async {
    try {
      // Connect to cloud API using HTTPS
      final cloudResponse = await http.get(Uri.parse('https://api.example.com/data'));
      if (cloudResponse.statusCode == 200) {
        print('Cloud Data: ${jsonDecode(cloudResponse.body)}');
      } else {
        throw Exception('Failed to load cloud data');
      }

      // Connect to local IoT device using HTTP
      final iotResponse = await http.get(Uri.parse('http://192.168.x.x/data'));
      if (iotResponse.statusCode == 200) {
        print('IoT Data: ${jsonDecode(iotResponse.body)}');
      } else {
        throw Exception('Failed to load IoT data');
      }
    } catch (e) {
      print('Error: $e');
    }
  }
}